/** @jsx jsx */

import React, { Fragment as _, useState, useRef } from 'react';
import { css, jsx } from '@emotion/core';
import getStore from 'services/getStore';
import { colors } from 'styles/variables';
import EditorBtn from 'components/UI/EditorBtn';
import { Block } from 'factories/block';
import {
  AudioUploadStatus,
  AudioUploadStatusWithProgress,
} from './AudioUploadStatus';

const store = getStore();
const URL_PREFIX = window['chameleon'].CHAMELEON_URL;

const { lPink, lGrey0, lGrey1 } = colors;

interface IAudioUploader {
  audioSrc: string;
  audioId?: string | number;
  setBlock: (block, data) => void;
  block: Block;
  setUploadError?: (err: string) => void;
}

const AudioUploader = ({
  audioSrc,
  audioId,
  setBlock,
  block,
  setUploadError,
}: IAudioUploader) => {
  //
  const [uploadStatus, setUploadStatus] = useState<{
    progress: number | undefined;
    uploading: boolean;
    processing: boolean;
    ready: boolean;
    error: boolean;
  }>({
    progress: undefined,
    uploading: false,
    processing: false,
    ready: false,
    error: false,
  });

  const audioFileInput = useRef<any>(null);
  const uploadToD3Controller = useRef<AbortController>();
  const abort = useRef<() => void>(() => {});

  let audioSrcFileName: string[] | string = audioSrc
    ? audioSrc.split(/\//g)
    : [];
  if (audioSrcFileName.length) {
    audioSrcFileName = audioSrcFileName[audioSrcFileName.length - 1];
  }

  return (
    <_>
      <input
        ref={audioFileInput}
        type="file"
        style={{
          display: 'none',
        }}
        onChange={e => {
          e.persist();

          const targetFiles = (e.target as any).files;

          const formData = new FormData();
          const files = Array.from(targetFiles);

          let isMP3;

          files.forEach((file: any) => {
            const { name } = file;

            const ext = name.split(/\./g);
            isMP3 = ['mp3', 'MP3'].includes(ext[ext.length - 1]);

            if (!isMP3) {
              return;
            }

            formData.append('file', file);
            formData.append('name', file.name);
            formData.append('project_id', store.getState().projectId || 697);
          });

          if (!isMP3) {
            // console.warn('The selected file is not an mp3. Aborting process.');
            audioFileInput.current.value = null;

            alert(
              'The file you are trying to upload is not supported. Ensure the file type is an mp3.'
            );

            return;
          }

          setUploadStatus({
            ...uploadStatus,
            uploading: true,
          });

          uploadToD3Controller.current = new AbortController();
          const uploadToD3ControllerSignal =
            uploadToD3Controller.current.signal;

          let signedId_;

          import('services/doDirectUpload')
            .then(({ doDirectUpload }) => {
              return doDirectUpload(
                files[0],
                uploadToD3ControllerSignal,
                progressEvent => {
                  // console.log(
                  //   `${progressEvent.type}: ${progressEvent.loaded} bytes transferred. ${progressEvent.total} bytes total`
                  // );

                  const percentCompleted = Math.round(
                    (progressEvent.loaded * 100) / progressEvent.total
                  );

                  setUploadStatus(uploadStatus => ({
                    ...uploadStatus,
                    progress: percentCompleted,
                    ...(percentCompleted >= 99 && {
                      processing: true,
                    }),
                  }));
                }
              );
            })
            .then(signedId => {
              signedId_ = signedId;
              formData.append('signed_id', (signedId as unknown) as string);
              return fetch(`${URL_PREFIX}/api/v2/media`, {
                body: formData,
                cache: 'no-cache',
                credentials: 'include',
                method: 'POST',
                mode: 'cors',
                referrer: 'no-referrer',
                signal: uploadToD3ControllerSignal,
              }).then(resp => {
                //

                if (resp.status >= 400) {
                  throw new Error();
                }

                return resp.json();
              });
            })
            .then((result: any) => {
              // we have finished and are ready to go
              setUploadStatus(uploadStatus => ({
                ...uploadStatus,
                ready: true,
              }));

              //
              // console.log(result);

              requestAnimationFrame(() => {
                audioFileInput.current.value = null;
                //
                setBlock(block, {
                  audioSrc: result.url,
                  audioIdV2: result.file.id,
                });
              });
            })
            .catch(err => {
              // ' whoopsy !!!'
              console.log(err);

              setUploadStatus(uploadStatus => ({
                ...uploadStatus,
                error: true,
              }));
            });
        }}
      />

      <div
        css={css({
          display: 'flex',
          alignItems: 'center',
        })}
      >
        <EditorBtn
          label="Insert audio"
          style={{
            width: '175px',
            margin: '0 15px 0 0',
            border: `1px solid ${lGrey0}`,
            background: '#fff',
            color: lGrey0,
            fontSize: 11,

            hover: {
              color: '#fff',
              background: '#28292b',
            },
          }}
          css={css`
            flex-shrink: 0;
            min-height: 30px;
          `}
          onClick={() => {
            audioFileInput.current.click();
          }}
        />
      </div>

      {uploadStatus.uploading && (
        <AudioUploadStatus
          uploadStatus={uploadStatus}
          onCancel={() => {
            if (uploadToD3Controller.current) {
              uploadToD3Controller.current.abort();
            }

            audioFileInput.current.value = null;
            //
            abort.current();
            // console.log('canceled');
          }}
          onClose={() => {
            audioFileInput.current.value = null;

            setUploadStatus({
              progress: 0,
              uploading: false,
              processing: false,
              ready: false,
              error: false,
            });
          }}
        />
      )}
    </_>
  );
};

export { AudioUploader };
